import{_ as n,g as a,h as i,S as e}from"./chunks/vitepress-theme-teek.DYsc1jHb.js";const g=JSON.parse('{"title":"一次由 Product Sense 驱动的 Agent 极限实践","description":"摘要总结：AI 时代，写好代码只是及格线。在一次极限挑战赛中，我们通过对 K12 赛道用户痛点的精准“视角切换”，打造出一款授人以渔的“数学辅导导师”并斩获大奖。本文复盘了 Agent 搭建背后的核心 SOP 设计逻辑：技术终究要回归对真实人性的体察与关怀。","frontmatter":{"date":"2024-06-14T22:00:00.000Z","title":"一次由 Product Sense 驱动的 Agent 极限实践","description":"摘要总结：AI 时代，写好代码只是及格线。在一次极限挑战赛中，我们通过对 K12 赛道用户痛点的精准“视角切换”，打造出一款授人以渔的“数学辅导导师”并斩获大奖。本文复盘了 Agent 搭建背后的核心 SOP 设计逻辑：技术终究要回归对真实人性的体察与关怀。","coverImg":"/img/cover/llm_learning_bg_2.png","permalink":"/ai-practice/math-bot","categories":["ai-practice"],"tags":["Agent","产品 Sense"]},"headers":[],"relativePath":"20.AI 学习与实践/04.社区活动与实践小项目/60.数学小助手.md","filePath":"20.AI 学习与实践/04.社区活动与实践小项目/60.数学小助手.md"}'),p={name:"20.AI 学习与实践/04.社区活动与实践小项目/60.数学小助手.md"};function l(t,s,r,h,k,o){return i(),a("div",null,[...s[0]||(s[0]=[e(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /20.AI 学习与实践/04.社区活动与实践小项目/60.数学小助手.md for this page in Markdown format</div><h1 id="一次由-product-sense-驱动的-agent-极限实践" tabindex="-1">一次由 Product Sense 驱动的 Agent 极限实践 <a class="header-anchor" href="#一次由-product-sense-驱动的-agent-极限实践" aria-label="Permalink to “一次由 Product Sense 驱动的 Agent 极限实践”">​</a></h1><blockquote><p><strong>摘要总结</strong>：AI 时代，写好代码只是及格线。在一次极限挑战赛中，我们通过对 K12 赛道用户痛点的精准“视角切换”，打造出一款授人以渔的“数学辅导导师”并斩获大奖。本文复盘了 Agent 搭建背后的核心 SOP 设计逻辑：技术终究要回归对真实人性的体察与关怀。</p></blockquote><p>在刚刚过去的周末，我和好友参加了一场由千帆 Agent 举办的线下社区活动。这是一场充满极客精神的“极限挑战”——我们需要在极其有限的时间内，从零开始构思、搭建并现场展示一个完整的 Agent 应用。</p><p>令人惊喜的是，我们不仅顺利完成了极限开发，最终还斩获了全场的<strong>「最佳应用奖」</strong>。</p><p>复盘这次短暂却高密度的开发体验，最大的感触是：在 AI 时代，单纯的工程实现已经不再是唯一的壁垒，真正让应用脱颖而出的，是对真实业务场景的洞察力。当 (Engineering + Product) × AI 的飞轮开始转动时，技术才能真正转化为解决问题的利器。</p><p>以下是关于这次“K12 数学小助手” Agent 搭建的实践总结与思考。</p><h2 id="_1-破局点-面对-k12-赛道-谁才是真正的用户" tabindex="-1">1. 破局点：面对 K12 赛道，谁才是真正的用户？ <a class="header-anchor" href="#_1-破局点-面对-k12-赛道-谁才是真正的用户" aria-label="Permalink to “1. 破局点：面对 K12 赛道，谁才是真正的用户？”">​</a></h2><p>活动给定的命题是“K12 教育”。在极限开发的时间压力下，最容易陷入的思维陷阱就是“直线思考”——既然是 K12，那就直接做一个给学生用的解题机器人。</p><p>但这恰恰违背了产品的核心逻辑。从受众角度来看，<strong>直接面向心智尚未成熟的 K12 学生提供一个“答案生成器”，极易沦为应付作业的作弊工具，既得不到学校的认可，也会引发家长的担忧。</strong></p><p>因此，在选题阶段，我们进行了一次关键的<strong>视角切换：将目标用户从“学生”转移到了“家长和老师”</strong>。</p><p>当代家长在辅导孩子尤其是数学作业时，最大的<strong>痛点往往不是“不知道答案”，而是“不知道如何科学地给孩子讲解”</strong>。基于这个 Product Sense，我们确定了 Agent 的核心定位——<strong>它不是一个冷冰冰的解题机，而是一位帮助家长掌握科学辅导方法的“幕后导师”</strong>。</p><h2 id="_2-为什么选择-数学-——-技术边界与场景的完美契合" tabindex="-1">2. 为什么选择“数学”？—— 技术边界与场景的完美契合 <a class="header-anchor" href="#_2-为什么选择-数学-——-技术边界与场景的完美契合" aria-label="Permalink to “2. 为什么选择“数学”？—— 技术边界与场景的完美契合”">​</a></h2><p>在众多的 K12 学科中，我们最终锁定了“数学”，这并非偶然，而是基于对大语言模型（LLM）能力边界的清晰认知：</p><ul><li><p><strong>规避“幻觉”的工程解法</strong>：众所周知，纯文本大模型在进行严谨的逻辑推演和数学计算时，极易产生“幻觉”。但自定义 Agent 拥有调用外部工具（尤其是代码解释器 Code Interpreter）的能力。这意味着我们可以让 Agent 通过编写和执行代码来处理复杂的数学计算，从而在架构层面保证了结果的准确性。</p></li><li><p><strong>满足“解题”与“解释”的双重需求</strong>：数学不仅仅是得出正确答案，更重要的是推导过程。Agent 可以并发处理双重任务——一方面在后台精准计算，另一方面在前台用自然语言将解题思路拆解为通俗易懂的“人话”，提供全面的教学辅助。</p></li></ul><h2 id="_3-agent-核心设计-结构化的-prompt-规范" tabindex="-1">3. Agent 核心设计：结构化的 Prompt 规范 <a class="header-anchor" href="#_3-agent-核心设计-结构化的-prompt-规范" aria-label="Permalink to “3. Agent 核心设计：结构化的 Prompt 规范”">​</a></h2><p>确定了产品方向后，接下来的重点就是“规范驱动” Prompt 设计。为了让 Agent 稳定输出高质量的内容，我们对其角色、工作流、工具链和限制条件进行了严格的定义。以下是我们在比赛中使用的核心 Prompt 设计：</p><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># 角色任务</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">你是一位经验丰富的小学数学教师，专注于帮助家长掌握科学的数学辅导方法。你的核心目标是引导家长理解问题背后的思维逻辑，提升他们协助孩子分析与解决问题的能力，真正做到“授人以渔”，同时还能够举一反三。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">在回应家长提问时，请严格遵循以下三步流程：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Step1：拆解问题——清晰梳理解题思路，指导家长如何一步步引导孩子理解题目本质，强调关键思考节点。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Step2：类比拓展——通过“百度搜索”工具查找与当前问题相似的典型例题或变式题，提供可参考的同类问题，帮助家长举一反三。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Step3：趣味延伸——结合“知识库”和网络资源，挖掘该知识点在真实生活或工作中的趣味应用案例、小故事或数据，并以幽默生动、通俗易懂的方式呈现，激发孩子对数学的兴趣；此部分需以“额外说明：”为前缀。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># 工具能力</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 图像内容理解：当用户上传含题目的图片时，调用图像理解工具准确识别题目内容，结合文字描述进行综合分析。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 百度搜索：用于查找相似题型、教学案例或生活应用场景，确保信息时效性与多样性。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 代码解释器：可用于验证计算过程或生成可视化图表辅助讲解。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># 要求与限制</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 语言风格：亲切自然，避免学术化术语，适合家长理解并转述给孩子。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 内容准确性：所有知识点、解题步骤及案例必须正确无误，严禁虚构或误导。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 安全性：不涉及任何敏感话题，不传播错误价值观。</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 多模态表达：根据需要灵活使用文字、示意图、音视频建议等方式，增强讲解效果。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># 示例</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">用户：孩子做应用题总是读不懂题意，怎么办？</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">回复：别急，这其实是很多孩子的“共性难题”！我们可以这样一步步来：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">第一步：帮孩子圈出关键词，比如“一共”“剩下”“每盒”等，这些就是解题的“导航灯”；</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">第二步：画个简单的图示（比如用方框代表盒子，小圆点代表物品），把抽象问题变成看得见的画面；</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">第三步：找一道类似的题试试看——我刚查到一个“分糖果”的经典题，特别适合练习理解题意；</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">额外说明：你知道吗？超市里算打折优惠，其实就是在用“百分数”！有个小朋友曾用这个算出了妈妈买奶茶省了多少钱，还被夸“数学小管家”呢～</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><p>设计巧思解析：</p><ul><li><p><strong>三步走工作流（SOP）</strong>：通过 <code>拆解 -&gt; 类比 -&gt; 延伸</code> 的强制性流程，保证了输出内容的结构化与教育深度，这不仅仅是解答，更是一套微型的教学法。</p></li><li><p><strong>工具的有机结合</strong>：引入 <code>图像理解</code> 工具，解决了家长“拍照问答”的高频交互需求；<code>百度搜索</code> 保证了变式题和趣味延伸的素材新鲜度；<code>代码解释器</code> 则是数学准确率的护城河。</p></li></ul><p>至此，整个 Agent 设计就基本完成，于是我们快速使用千帆提供的 SDK，编码实现了 Agent 的功能，然后将其部署到了千帆提供的平台。</p><h2 id="_4-总结-从研发思维到产品直觉" tabindex="-1">4. 总结：从研发思维到产品直觉 <a class="header-anchor" href="#_4-总结-从研发思维到产品直觉" aria-label="Permalink to “4. 总结：从研发思维到产品直觉”">​</a></h2><p>在 Demo 演示环节，当我们输入“孩子做应用题总是读不懂题意，怎么办？”时，Agent 并没有干巴巴地罗列知识点，而是像一位耐心的老教师一样，教家长如何圈出“一共”、“剩下”这些“导航灯”，并顺手推送了一道经典的“分糖果”变式题，甚至还补充了超市打折算百分比的生活趣味案例。</p><p>那一刻，台下的反响印证了我们最初的判断：<strong>打动人心的永远不是冷峻的技术指标，而是技术对真实人性的体察与关怀</strong>。</p><p>这次获奖是一次非常棒的验证，它让我更加确信，在 AI 赋能的开发流中，写好代码只是及格线。拥有对业务痛点的敏锐嗅觉，并利用大模型组合出优雅的解决方案，才是我们在未来应当持续修炼的内功。</p>`,25)])])}const c=n(p,[["render",l]]);export{g as __pageData,c as default};
